function calcPoints(d) {
  let p=0;
  if(d.brushAM)p+=10;if(d.brushPM)p+=10;if(d.floss)p+=10;
  if(d.shower)p+=10;if(d.shave)p+=10;
  if(d.groom)p+=10;if(d.sunscreen)p+=10;if(d.nap)p+=15;if(d.breathing)p+=15;
  (d.workouts||[]).forEach(w=>{p+=[0,15,30,60][w]||0;});
  if(d.medicine)p+=10;p+=(d.bp?.length||0)*10;if(d.weight)p+=10;
  p+=[0,15,25,35][d.scripture]||0;
  if(d.prayer?.duration)p+=[0,15,25,35][d.prayer.duration]||0;
  p+=(d.emotions?.length||0)*10;if(d.connect)p+=30;
  if(d.planDay)p+=20;if(d.notifZero)p+=20;if(d.emailZero)p+=25;
  if(d.avoidedTask)p+=50;
  p+=[0,20,40,70][d.walk]||0;
  p+=Math.min(3,(d.journal?.length||0))*20;
  p+=[0,25,45,70][d.readBook]||0;
  if(d.meals?.breakfast)p+=10;if(d.meals?.lunch)p+=10;if(d.meals?.dinner)p+=10;
  p+=(d.snacks?.length||0)*3;if(d.tasteJournal)p+=10;
  if(d.cookMeal)p+=30;p+=(d.waterRefills||0)*5;if(d.platFood)p+=15;
  if(d.makeBed)p+=10;if(d.mowLawn)p+=80;
  p+=[0,20,40,70][d.cleaning?.tier]||0;
  return p;
}

const dm={bg:"#161314",card:"#231e20",card2:"#2e2729",border:"#3a3133",text:"#f0eaec",subtext:"#b8a8ac",hint:"#6e5a5e",green:"#d4889a",orange:"#c8a0a8",blue:"#a07888",red:"#c05060"};
const cs={
  wrap:{fontFamily:"-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif",maxWidth:680,margin:"0 auto",paddingBottom:100,background:dm.bg,minHeight:"100vh"},
  tabs:{display:"flex",background:dm.card,borderBottom:`0.5px solid ${dm.border}`,padding:"0 16px"},
  tab:a=>({flex:1,padding:"14px 8px",fontSize:15,fontWeight:a?500:400,color:a?dm.text:dm.hint,background:"none",border:"none",cursor:"pointer",borderBottom:a?`2px solid ${dm.text}`:"2px solid transparent"}),
  sec:{padding:"16px 16px 4px"},
  secHead:{fontSize:12,fontWeight:600,color:dm.hint,textTransform:"uppercase",letterSpacing:"0.08em"},
  card:{background:dm.card,borderRadius:14,marginBottom:10,overflow:"hidden"},
  row:{display:"flex",alignItems:"center",justifyContent:"space-between",gap:12,padding:"14px 16px",minHeight:56},
  lbl:{fontSize:16,flex:1,color:dm.text},
  pts:{fontSize:13,color:dm.green,fontWeight:500,minWidth:32,textAlign:"right"},
  tog:on=>({width:52,height:30,borderRadius:15,border:"none",cursor:"pointer",background:on?dm.green:"#3a3133",position:"relative",transition:"background 0.2s",flexShrink:0}),
  dot:on=>({position:"absolute",top:3,left:on?25:3,width:24,height:24,borderRadius:12,background:"#fff",transition:"left 0.2s",boxShadow:"0 1px 3px rgba(0,0,0,0.4)",display:"flex",alignItems:"center",justifyContent:"center"}),
  chip:a=>({padding:"8px 14px",borderRadius:20,border:"1px solid",fontSize:14,cursor:"pointer",background:a?dm.text:"transparent",color:a?dm.bg:dm.text,borderColor:a?dm.text:dm.hint,minHeight:36,display:"inline-flex",alignItems:"center",position:"relative"}),
  inp:{width:"100%",padding:"12px 14px",borderRadius:12,border:`1px solid ${dm.border}`,fontSize:16,boxSizing:"border-box",background:dm.card2,outline:"none",color:dm.text},
  cBtn:{width:40,height:40,borderRadius:12,border:`1px solid ${dm.border}`,background:dm.card2,cursor:"pointer",fontSize:20,display:"flex",alignItems:"center",justifyContent:"center",color:dm.text},
  badge:met=>({fontSize:12,padding:"4px 10px",borderRadius:99,background:met?"#3d1f28":"#3d2e28",color:met?dm.green:dm.orange,fontWeight:500}),
  overlay:{position:"fixed",inset:0,background:"rgba(0,0,0,0.7)",zIndex:100,display:"flex",flexDirection:"column",justifyContent:"flex-end"},
  sheet:{background:dm.card,borderRadius:"20px 20px 0 0",padding:"12px 20px 40px",maxHeight:"90vh",overflowY:"auto"},
  handle:{width:36,height:4,borderRadius:2,background:dm.hint,margin:"0 auto 16px"},
  sheetTitle:{fontSize:18,fontWeight:600,marginBottom:16,color:dm.text},
  bigBtn:a=>({width:"100%",padding:"15px",borderRadius:14,border:"1px solid",fontSize:16,fontWeight:500,cursor:"pointer",background:a?dm.text:"transparent",color:a?dm.bg:dm.text,borderColor:a?dm.text:dm.hint}),
  divider:{height:"0.5px",background:dm.border,margin:"0 16px"},
};

const PtsBadge=({pts})=>(<span style={{position:"absolute",top:-6,right:-6,background:dm.green,color:dm.bg,fontSize:9,fontWeight:700,borderRadius:99,padding:"2px 4px",lineHeight:1}}>{pts}</span>);
const Dots=({count,total})=>(<div style={{display:"flex",gap:4}}>{Array.from({length:total}).map((_,i)=>(<div key={i} style={{width:8,height:8,borderRadius:4,background:count>i?dm.green:dm.border}}/>))}</div>);
const Toggle=({on,onChange,pts})=>(<button style={cs.tog(on)} onClick={()=>onChange(!on)}><div style={cs.dot(on)}>{pts&&<span style={{fontSize:9,fontWeight:700,color:dm.hint,lineHeight:1}}>{pts}</span>}</div></button>);
const Chevron=({open})=>(<svg width="18" height="18" viewBox="0 0 16 16" fill="none" style={{transition:"transform 0.2s",transform:open?"rotate(180deg)":"rotate(0deg)"}}><path d="M3 6l5 5 5-5" stroke={dm.hint} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/></svg>);
const RowItem=({label,pts:p,right,last})=>(<><div style={cs.row}><span style={cs.lbl}>{label}</span>{p>0&&<span style={cs.pts}>+{p}</span>}{right}</div>{!last&&<div style={cs.divider}/>}</>);
function parseMacro(str,key){if(!str)return 0;const pats={cal:/(\d+(?:\.\d+)?)\s*(?:calories?|cal)/i,pro:/(\d+(?:\.\d+)?)\s*g?\s*protein/i,carb:/(\d+(?:\.\d+)?)\s*g?\s*carbs?/i,fat:/(\d+(?:\.\d+)?)\s*g?\s*fat/i};const m=str.match(pats[key]);return m?Math.round(Number(m[1])):0;}
function CalorieDisplay({d}){const[showLog,setShowLog]=useState(false);const splitMeal=s=>s?s.split(' | '):[];const foods=[...splitMeal(d.meals?.breakfast),...splitMeal(d.meals?.lunch),...splitMeal(d.meals?.dinner),...(d.snacks||[])].filter(Boolean);const tot=foods.reduce((a,f)=>({cal:a.cal+parseMacro(f,'cal'),pro:a.pro+parseMacro(f,'pro'),carb:a.carb+parseMacro(f,'carb'),fat:a.fat+parseMacro(f,'fat')}),{cal:0,pro:0,carb:0,fat:0});const entries=[...splitMeal(d.meals?.breakfast).map((v,i)=>({label:i===0?"Breakfast":`Breakfast (${i+1})`,val:v})),...splitMeal(d.meals?.lunch).map((v,i)=>({label:i===0?"Lunch":`Lunch (${i+1})`,val:v})),...splitMeal(d.meals?.dinner).map((v,i)=>({label:i===0?"Dinner":`Dinner (${i+1})`,val:v})),...(d.snacks||[]).map((s,i)=>({label:(d.snacks.length>1?`Snack ${i+1}`:"Snack"),val:s}))];return(<><div style={{padding:"12px 16px 14px",borderBottom:`0.5px solid ${dm.border}`}}><div style={{position:"relative",textAlign:"center",marginBottom:10}}><span style={{fontSize:32,fontWeight:700,color:dm.text}}>{tot.cal}</span><span style={{fontSize:14,color:dm.subtext,marginLeft:5}}>cal today</span><button style={{position:"absolute",right:0,top:"50%",transform:"translateY(-50%)",background:"none",border:"none",cursor:"pointer",fontSize:12,color:dm.hint,padding:0}} onClick={()=>setShowLog(true)}>view log →</button></div><div style={{display:"flex",gap:8}}>{[["Protein",tot.pro],["Carbs",tot.carb],["Fat",tot.fat]].map(([lbl,val])=>(<div key={lbl} style={{flex:1,background:dm.card2,borderRadius:10,padding:"8px 0",textAlign:"center"}}><div style={{fontSize:18,fontWeight:600,color:dm.text}}>{val}g</div><div style={{fontSize:11,color:dm.hint,marginTop:2}}>{lbl}</div></div>))}</div></div>{showLog&&<Sheet title="Food log" onClose={()=>setShowLog(false)}>{entries.length===0?<p style={{fontSize:14,color:dm.hint,textAlign:"center",padding:"20px 0"}}>No meals logged yet.</p>:entries.map(({label,val},i)=>(<div key={i} style={{marginBottom:16}}><div style={{fontSize:12,color:dm.hint,marginBottom:3}}>{label}</div><div style={{fontSize:14,color:dm.text,lineHeight:1.5}}>{val}</div></div>))}</Sheet>}</>);}

function Sheet({title,onClose,children}){return(<div style={cs.overlay} onClick={e=>{if(e.target===e.currentTarget)onClose();}}><div style={cs.sheet}><div style={cs.handle}/><div style={cs.sheetTitle}>{title}</div>{children}</div></div>);}

// All sheet components (abbreviated for space — same as current app)
function WeightSheet({weight,onChange,onClose}){const[val,setVal]=useState(weight||"");return(<Sheet title="Log weight" onClose={onClose}><input style={cs.inp} placeholder="Weight (lbs)" value={val} onChange={e=>setVal(e.target.value)} type="number" autoFocus/><div style={{display:"flex",gap:10,marginTop:14}}><button style={{...cs.bigBtn(false),flex:1}} onClick={onClose}>Back</button><button style={{...cs.bigBtn(true),flex:1}} onClick={()=>{if(val){onChange(val);onClose();}}} disabled={!val}>Log</button></div></Sheet>);}
function BPSheet({bp,onChange,onClose}){const[sys,setSys]=useState("");const[dia,setDia]=useState("");return(<Sheet title="Blood pressure" onClose={onClose}><p style={{fontSize:14,color:dm.subtext,marginBottom:10}}>{bp.length}/2 readings today</p><input style={cs.inp} placeholder="Systolic" value={sys} onChange={e=>setSys(e.target.value)} type="number"/><input style={{...cs.inp,marginTop:10}} placeholder="Diastolic" value={dia} onChange={e=>setDia(e.target.value)} type="number"/><div style={{display:"flex",gap:10,marginTop:14}}><button style={{...cs.bigBtn(false),flex:1}} onClick={onClose}>Back</button><button style={{...cs.bigBtn(true),flex:1}} onClick={()=>{if(sys&&dia&&bp.length<2){onChange([...bp,{sys,dia,time:new Date().toLocaleTimeString([],{hour:"2-digit",minute:"2-digit"})}]);onClose();}}} disabled={!sys||!dia||bp.length>=2}>Log</button></div>{bp.map((r,i)=><p key={i} style={{fontSize:13,color:dm.subtext,marginTop:8}}>Reading {i+1}: {r.sys}/{r.dia} @ {r.time}</p>)}</Sheet>);}
function ScriptureSheet({d,tier,update,onClose}){const[note,setNote]=useState(d.scriptureNote||"");return(<Sheet title="Read scripture" onClose={onClose}><p style={{fontSize:14,color:dm.subtext,marginBottom:14}}>{["10 min","20 min","30+ min"][tier-1]}</p><textarea style={{...cs.inp,height:90,resize:"none"}} placeholder="What did you read? (optional)" value={note} onChange={e=>setNote(e.target.value)} autoFocus/><div style={{display:"flex",gap:10,marginTop:14}}><button style={{...cs.bigBtn(false),flex:1}} onClick={onClose}>Back</button><button style={{...cs.bigBtn(true),flex:1}} onClick={()=>{update({scripture:tier,scriptureNote:note});onClose();}}>Log</button></div></Sheet>);}
function PrayerSheet({d,tier,update,onClose}){const[topic,setTopic]=useState(d.prayer?.topic||"");return(<Sheet title="Prayer" onClose={onClose}><p style={{fontSize:14,color:dm.subtext,marginBottom:14}}>{["5 min","15 min","25+ min"][tier-1]}</p><input style={cs.inp} placeholder="Who or what did you pray for? (optional)" value={topic} onChange={e=>setTopic(e.target.value)} autoFocus/><div style={{display:"flex",gap:10,marginTop:14}}><button style={{...cs.bigBtn(false),flex:1}} onClick={onClose}>Back</button><button style={{...cs.bigBtn(true),flex:1}} onClick={()=>{update({prayer:{duration:tier,topic}});onClose();}}>Log</button></div></Sheet>);}
function WorkoutSheet({d,val,update,onClose}){const[note,setNote]=useState(d.workoutNote||"");const[pushups,setPushups]=useState(d.pushups||"");function commit(n){const cur=[...(d.workouts||[])];if(cur.filter(w=>w===val).length<2)cur.push(val);update({workouts:cur,workoutNote:n,pushups});onClose();}return(<Sheet title="Work out" onClose={onClose}><p style={{fontSize:14,color:dm.subtext,marginBottom:14}}>{["Light","Moderate","Intense"][val-1]}</p>{val===1&&(<div style={{marginBottom:14,padding:"12px 14px",background:dm.card2,borderRadius:12}}><label style={{fontSize:14,color:dm.subtext,display:"block",marginBottom:8}}>Push-ups</label><input style={cs.inp} type="number" placeholder="How many? (optional)" value={pushups} onChange={e=>setPushups(e.target.value)}/></div>)}<textarea style={{...cs.inp,height:80,resize:"none"}} placeholder="What did you do? (optional)" value={note} onChange={e=>setNote(e.target.value)} autoFocus/><div style={{display:"flex",gap:10,marginTop:14}}><button style={{...cs.bigBtn(false),flex:1}} onClick={onClose}>Back</button><button style={{...cs.bigBtn(true),flex:1}} onClick={()=>commit(note)}>Log</button></div></Sheet>);}
function ReadBookSheet({d,tier,update,onClose}){const[note,setNote]=useState(d.readBookNote||"");return(<Sheet title="Read a book" onClose={onClose}><p style={{fontSize:14,color:dm.subtext,marginBottom:14}}>{["20 min","40 min","60+ min"][tier-1]}</p><input style={cs.inp} placeholder="What are you reading? (optional)" value={note} onChange={e=>setNote(e.target.value)} autoFocus/><div style={{display:"flex",gap:10,marginTop:14}}><button style={{...cs.bigBtn(false),flex:1}} onClick={onClose}>Back</button><button style={{...cs.bigBtn(true),flex:1}} onClick={()=>{update({readBook:tier,readBookNote:note});onClose();}}>Log</button></div></Sheet>);}
function AvoidedTaskSheet({d,update,onClose}){const[task,setTask]=useState(d.avoidedTaskNote||"");return(<Sheet title="Complete avoided task" onClose={onClose}><input style={cs.inp} placeholder="What task did you complete? (optional)" value={task} onChange={e=>setTask(e.target.value)} autoFocus/><div style={{display:"flex",gap:10,marginTop:14}}><button style={{...cs.bigBtn(false),flex:1}} onClick={onClose}>Back</button><button style={{...cs.bigBtn(true),flex:1}} onClick={()=>{update({avoidedTask:true,avoidedTaskNote:task});onClose();}}>Slay</button></div></Sheet>);}
function ConnectSheet({d,update,onClose}){const[who,setWho]=useState(d.connectNote||"");return(<Sheet title="Connect with someone" onClose={onClose}><input style={cs.inp} placeholder="Who did you connect with? (optional)" value={who} onChange={e=>setWho(e.target.value)} autoFocus/><div style={{display:"flex",gap:10,marginTop:14}}><button style={{...cs.bigBtn(false),flex:1}} onClick={onClose}>Back</button><button style={{...cs.bigBtn(true),flex:1}} onClick={()=>{update({connect:true,connectNote:who});onClose();}}>Heyyy</button></div></Sheet>);}
function TasteJournalSheet({d,update,onClose}){const[val,setVal]=useState(d.tasteJournal||"");return(<Sheet title="Taste journal" onClose={onClose}><textarea style={{...cs.inp,height:100,resize:"none"}} placeholder="Describe the eating experience..." value={val} onChange={e=>setVal(e.target.value)} autoFocus/><div style={{display:"flex",gap:10,marginTop:14}}><button style={{...cs.bigBtn(false),flex:1}} onClick={onClose}>Back</button><button style={{...cs.bigBtn(true),flex:1}} onClick={()=>{update({tasteJournal:val});onClose();}}>Yummy</button></div></Sheet>);}
function CleaningSheet({d,tier,update,onClose}){const[subs,setSubs]=useState(d.cleaning?.subs||[]);const toggleSub=s=>setSubs(p=>p.includes(s)?p.filter(x=>x!==s):[...p,s]);return(<Sheet title="Cleaning session" onClose={onClose}><p style={{fontSize:14,color:dm.subtext,marginBottom:14}}>{["10 min","30 min","60+ min"][tier-1]}</p><p style={{fontSize:14,color:dm.subtext,marginBottom:10}}>What was cleaned?</p><div style={{display:"flex",flexWrap:"wrap",gap:8}}>{CLEANING_SUBS.map(s=><button key={s} style={cs.chip(subs.includes(s))} onClick={()=>toggleSub(s)}>{s}</button>)}</div><div style={{display:"flex",gap:10,marginTop:20}}><button style={{...cs.bigBtn(false),flex:1}} onClick={onClose}>Back</button><button style={{...cs.bigBtn(true),flex:1}} onClick={()=>{update({cleaning:{tier,subs}});onClose();}}>Log</button></div></Sheet>);}

function EmotionWheel({onSelect}){const[step,setStep]=useState(1);const[core,setCore]=useState(null);const[mid,setMid]=useState(null);const coreBtn=(name,color)=>({padding:"10px 14px",borderRadius:12,border:`2px solid ${color}`,cursor:"pointer",background:"transparent",color:"#fff",fontSize:14,fontWeight:600,textAlign:"center"});const midBtn=(color)=>({padding:"9px 13px",borderRadius:10,border:`1px solid ${color}88`,cursor:"pointer",background:`${color}22`,color:"#fff",fontSize:13,fontWeight:500,textAlign:"center"});const specBtn=(color)=>({padding:"9px 13px",borderRadius:10,border:`1px solid ${color}55`,cursor:"pointer",background:`${color}15`,color:"#fff",fontSize:13,textAlign:"center"});if(step===1)return(<div><p style={{fontSize:14,color:dm.subtext,marginBottom:12}}>How are you feeling?</p><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8}}>{CORE_EMOTIONS.map(name=>(<button key={name} style={coreBtn(name,WHEEL[name].color)} onClick={()=>{setCore(name);setStep(2);}}>{name}</button>))}</div></div>);if(step===2)return(<div><button onClick={()=>setStep(1)} style={{background:"none",border:"none",color:dm.hint,cursor:"pointer",fontSize:13,marginBottom:12,padding:0}}>← {core}</button><p style={{fontSize:14,color:dm.subtext,marginBottom:12}}>More specifically...</p><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8}}>{Object.keys(WHEEL[core].mid).map(name=>(<button key={name} style={midBtn(WHEEL[core].color)} onClick={()=>{setMid(name);setStep(3);}}>{name}</button>))}</div></div>);return(<div><button onClick={()=>setStep(2)} style={{background:"none",border:"none",color:dm.hint,cursor:"pointer",fontSize:13,marginBottom:12,padding:0}}>← {core} / {mid}</button><p style={{fontSize:14,color:dm.subtext,marginBottom:12}}>Even more specifically...</p><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8}}>{WHEEL[core].mid[mid].map(name=>(<button key={name} style={specBtn(WHEEL[core].color)} onClick={()=>onSelect({core,mid,specific:name})}>{name}</button>))}</div></div>);}
function EmotionSheet({emotions,onChange,onClose}){const[selected,setSelected]=useState(null);const[note,setNote]=useState("");function log(){onChange([...emotions,{...selected,note,time:new Date().toLocaleTimeString([],{hour:"2-digit",minute:"2-digit"})}]);onClose();}return(<Sheet title={`Emotional check-in ${emotions.length}/4`} onClose={onClose}>{emotions.length>=4?<p style={{fontSize:15,color:dm.subtext}}>You have logged 4 check-ins today.</p>:(<><EmotionWheel onSelect={setSelected}/>{selected&&(<div style={{marginTop:12,padding:"12px 14px",background:dm.card2,borderRadius:12}}><p style={{fontSize:14,fontWeight:500,margin:"0 0 8px",color:dm.text}}>{selected.core} - {selected.mid} - {selected.specific}</p><textarea placeholder="Optional note..." value={note} onChange={e=>setNote(e.target.value)} style={{...cs.inp,height:70,resize:"none"}}/><button style={{...cs.bigBtn(true),marginTop:10}} onClick={log}>Log this feeling</button></div>)}</>)}</Sheet>);}
function JournalSheet({d,update,onClose}){const usedPrompts=(d.journal||[]).map(e=>e.prompt);const pool=PROMPTS.filter(p=>!usedPrompts.includes(p));const available=pool.length>0?pool:PROMPTS;const getPrompt=()=>available[Math.floor(Math.random()*available.length)];const[prompt,setPrompt]=useState(()=>getPrompt());const[response,setResponse]=useState("");const count=(d.journal||[]).length;function reroll(){setPrompt(getPrompt());setResponse("");}function log(){if(!response.trim())return;update({journal:[...(d.journal||[]),{prompt,response,time:new Date().toLocaleTimeString([],{hour:"2-digit",minute:"2-digit"})}]});onClose();}return(<Sheet title="Journal" onClose={onClose}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10}}><p style={{fontSize:12,color:dm.hint,margin:0}}>Entry {count+1} · +20pts</p><button onClick={reroll} style={{background:"none",border:`1px solid ${dm.border}`,borderRadius:8,padding:"4px 10px",fontSize:12,color:dm.subtext,cursor:"pointer"}}>Nope!</button></div><div style={{padding:"14px",background:dm.card2,borderRadius:12,marginBottom:14}}><p style={{fontSize:16,color:dm.text,lineHeight:1.6,margin:0}}>{prompt}</p></div><textarea style={{...cs.inp,height:140,resize:"none"}} placeholder="Write your response..." value={response} onChange={e=>setResponse(e.target.value)} autoFocus/><div style={{display:"flex",gap:10,marginTop:14}}><button style={{...cs.bigBtn(false),flex:1}} onClick={onClose}>Back</button><button style={{...cs.bigBtn(true),flex:1}} onClick={log} disabled={!response.trim()}>Spill it</button></div></Sheet>);}

async function estimateCalories({text,imageBase64,imageType,apiKey}){const content=[];if(imageBase64)content.push({type:"image",source:{type:"base64",media_type:imageType,data:imageBase64}});const prompt=imageBase64&&text?`Food photo + description: "${text}". Reply in one sentence only: name the food, then calories and macros. Example: "Grilled chicken breast (~165 cal, 31g protein, 0g carbs, 4g fat)."`:imageBase64?`Reply in one sentence only: name the food in this photo, then calories and macros. Example: "Grilled chicken breast (~165 cal, 31g protein, 0g carbs, 4g fat)."`:` Reply in one sentence only: name the food, then calories and macros for "${text}". Example: "Grilled chicken breast (~165 cal, 31g protein, 0g carbs, 4g fat)."` ;content.push({type:"text",text:prompt});const res=await fetch("/api/estimate",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({apiKey,model:"claude-haiku-4-5-20251001",max_tokens:300,messages:[{role:"user",content}]})});const data=await res.json();if(!res.ok)throw new Error(data.error?.message||"API error");return data.content?.[0]?.text||"";}
function FoodSheet({title,initialValue,onSave,onClose,apiKey,offerTaste,onTaste}){const[step,setStep]=useState(1);const[text,setText]=useState(initialValue||"");const[imgB64,setImgB64]=useState(null);const[imgType,setImgType]=useState(null);const[imgPrev,setImgPrev]=useState(null);const[estimate,setEstimate]=useState("");const[estimating,setEstimating]=useState(false);const[err,setErr]=useState("");const[tasteText,setTasteText]=useState("");const[manCal,setManCal]=useState("");const[manPro,setManPro]=useState("");const[manCarb,setManCarb]=useState("");const[manFat,setManFat]=useState("");const fileRef=useRef();function handleFile(e){const file=e.target.files?.[0];if(!file)return;const r=new FileReader();r.onload=ev=>{const d=ev.target.result;setImgB64(d.split(",")[1]);setImgType(file.type);setImgPrev(d);setEstimate("");};r.readAsDataURL(file);}async function runEstimate(){if(!apiKey){setErr("Add your API key in Settings first.");return;}if(!text&&!imgB64){setErr("Add a description or photo first.");return;}setEstimating(true);setErr("");setEstimate("");try{const r=await estimateCalories({text,imageBase64:imgB64,imageType:imgType,apiKey});setEstimate(r);}catch(e){setErr(e.message);}setEstimating(false);}function handleLog(){if(!text&&!imgB64)return;let ms=estimate;if(!ms){const p=[];if(manCal)p.push(manCal+' calories');if(manPro)p.push(manPro+'g protein');if(manCarb)p.push(manCarb+'g carbs');if(manFat)p.push(manFat+'g fat');if(p.length)ms=p.join(', ');}onSave(ms?`${text||""}${text?" - ":""}${ms}`:text);if(offerTaste)setStep(2);else onClose();}if(step===2)return(<Sheet title="Taste journal" onClose={onClose}><p style={{fontSize:15,color:dm.subtext,marginBottom:12}}>Earn 10pts - describe the experience intentionally.</p><textarea style={{...cs.inp,height:100,resize:"none"}} placeholder="How did it taste? Were you present?" value={tasteText} onChange={e=>setTasteText(e.target.value)} autoFocus/><div style={{display:"flex",gap:10,marginTop:14}}><button style={{...cs.bigBtn(false),flex:1}} onClick={onClose}>I'll pass</button><button style={{...cs.bigBtn(true),flex:1}} onClick={()=>{if(tasteText)onTaste(tasteText);onClose();}} disabled={!tasteText}>Yummy</button></div></Sheet>);return(<Sheet title={title} onClose={onClose}><input style={cs.inp} placeholder="Describe what you ate..." value={text} onChange={e=>setText(e.target.value)} autoFocus/><div style={{display:"flex",gap:6,marginTop:10}}>{[["Cal",manCal,setManCal],["Protein",manPro,setManPro],["Carbs",manCarb,setManCarb],["Fat",manFat,setManFat]].map(([lbl,val,set])=>(<div key={lbl} style={{flex:1,textAlign:"center"}}><div style={{fontSize:11,color:dm.hint,marginBottom:3}}>{lbl}</div><input style={{width:"100%",padding:"7px 2px",borderRadius:8,border:`1px solid ${dm.border}`,background:dm.card2,color:dm.text,fontSize:14,textAlign:"center",boxSizing:"border-box",outline:"none"}} type="number" placeholder="—" value={val} onChange={e=>set(e.target.value)}/></div>))}</div><div style={{display:"flex",gap:10,marginTop:10}}><button style={{...cs.bigBtn(!!imgB64),flex:1,fontSize:14}} onClick={()=>fileRef.current.click()}>{imgB64?"Photo added":"Upload photo"}</button><input ref={fileRef} type="file" accept="image/*" style={{display:"none"}} onChange={handleFile}/><button style={{...cs.bigBtn(false),flex:1,fontSize:14,opacity:estimating?0.5:1}} onClick={runEstimate} disabled={estimating||(!text&&!imgB64)}>{estimating?"Estimating...":"Estimate cals"}</button></div>{imgPrev&&<img src={imgPrev} alt="food" style={{width:"100%",borderRadius:12,marginTop:10,maxHeight:180,objectFit:"cover"}}/>}{err&&<p style={{fontSize:13,color:dm.red,marginTop:8}}>{err}</p>}{estimate&&<div style={{marginTop:10,padding:"12px 14px",background:dm.card2,borderRadius:12,fontSize:14,color:dm.text,lineHeight:1.6}}>{estimate}</div>}<div style={{display:"flex",gap:10,marginTop:14}}><button style={{...cs.bigBtn(false),flex:1}} onClick={onClose}>Back</button><button style={{...cs.bigBtn(true),flex:1}} onClick={handleLog} disabled={!text&&!imgB64}>Log</button></div></Sheet>);}

function Section({label,open,onToggle,children}){return(<div style={{marginBottom:10}}><button onClick={onToggle} style={{display:"flex",alignItems:"center",justifyContent:"space-between",width:"100%",background:"none",border:"none",cursor:"pointer",padding:"0 0 8px 0"}}><span style={cs.secHead}>{label}</span><Chevron open={open}/></button>{open&&<div style={cs.card}>{children}</div>}</div>);}

function SearchBar({setModal,d,update,onClose}){const[query,setQuery]=useState("");const inputRef=useRef();useEffect(()=>{inputRef.current?.focus();},[]);const ALL=[{label:"Brush teeth AM",section:"Body",key:"brushAM",type:"toggle"},{label:"Brush teeth PM",section:"Body",key:"brushPM",type:"toggle"},{label:"Floss",section:"Body",key:"floss",type:"toggle"},{label:"Shower",section:"Body",key:"shower",type:"toggle"},{label:"Shave",section:"Body",key:"shave",type:"toggle"},{label:"Work out - Light",section:"Body",modal:"workout-1"},{label:"Work out - Moderate",section:"Body",modal:"workout-2"},{label:"Work out - Intense",section:"Body",modal:"workout-3"},{label:"Groom intentionally",section:"Body",key:"groom",type:"toggle"},{label:"Apply sunscreen",section:"Body",key:"sunscreen",type:"toggle"},{label:"Intentional nap",section:"Body",key:"nap",type:"toggle"},{label:"Breathing exercise",section:"Body",key:"breathing",type:"toggle"},{label:"Take medicine",section:"Health",key:"medicine",type:"toggle"},{label:"Blood pressure",section:"Health",modal:"bp"},{label:"Log weight",section:"Health",modal:"weight"},{label:"Read scripture",section:"Soul",modal:"scripture-1"},{label:"Prayer",section:"Soul",modal:"prayer-1"},{label:"Emotional check-in",section:"Soul",modal:"emotion"},{label:"Connect with someone",section:"Soul",modal:"connect"},{label:"Plan your day",section:"Mind",key:"planDay",type:"toggle"},{label:"Notifications to zero",section:"Mind",key:"notifZero",type:"toggle"},{label:"Email to zero",section:"Mind",key:"emailZero",type:"toggle"},{label:"Complete avoided task",section:"Mind",modal:"avoidedTask"},{label:"Phone-free walk",section:"Mind",key:"walk",val:1,type:"value"},{label:"Journal",section:"Mind",modal:"journal"},{label:"Read a book",section:"Mind",modal:"readBook-1"},{label:"Log breakfast",section:"Food",modal:"meal-breakfast"},{label:"Log lunch",section:"Food",modal:"meal-lunch"},{label:"Log dinner",section:"Food",modal:"meal-dinner"},{label:"Log snack",section:"Food",modal:"snack"},{label:"Cook a meal at home",section:"Food",key:"cookMeal",type:"toggle"},{label:"Plate your food nicely",section:"Food",key:"platFood",type:"toggle"},{label:"Water refill",section:"Food",key:"waterRefills",type:"increment"},{label:"Make bed",section:"Home",key:"makeBed",type:"toggle"},{label:"Mow the lawn",section:"Home",key:"mowLawn",type:"toggle"},{label:"Cleaning session",section:"Home",modal:"cleaning-1"}];const results=query.trim().length===0?[]:ALL.filter(i=>i.label.toLowerCase().includes(query.toLowerCase())||i.section.toLowerCase().includes(query.toLowerCase()));function select(item){if(item.type==="toggle")update({[item.key]:!d[item.key]});else if(item.type==="value")update({[item.key]:item.val});else if(item.type==="increment")update({[item.key]:(d[item.key]||0)+1});else if(item.modal)setModal(item.modal);onClose();}return(<div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.75)",zIndex:200,display:"flex",flexDirection:"column",justifyContent:"flex-start",paddingTop:60}}><div style={{background:dm.card,borderRadius:16,margin:"0 16px",padding:16,maxHeight:"75vh",overflowY:"auto"}}><div style={{display:"flex",gap:10,alignItems:"center",marginBottom:12}}><input ref={inputRef} style={{...cs.inp,marginTop:0,flex:1}} placeholder="Search habits..." value={query} onChange={e=>setQuery(e.target.value)}/><button style={{...cs.chip(false),flexShrink:0}} onClick={onClose}>Cancel</button></div>{query.trim().length===0&&<p style={{fontSize:14,color:dm.hint,textAlign:"center",padding:"12px 0"}}>Start typing to find a habit</p>}{query.trim().length>0&&results.length===0&&<p style={{fontSize:14,color:dm.hint,textAlign:"center",padding:"12px 0"}}>No results</p>}{results.map((item,i)=>(<div key={i}><button onClick={()=>select(item)} style={{width:"100%",background:"none",border:"none",cursor:"pointer",padding:"12px 4px",display:"flex",justifyContent:"space-between",alignItems:"center",textAlign:"left"}}><span style={{fontSize:16,color:dm.text}}>{item.label}</span><span style={{fontSize:12,color:dm.hint}}>{item.section}</span></button>{i<results.length-1&&<div style={cs.divider}/>}</div>))}</div></div>);}

function TodayView({d,update,setModal}){const[open,setOpen]=useState({body:true,health:true,soul:true,mind:true,food:true,home:true});const tog=k=>setOpen(o=>({...o,[k]:!o[k]}));const wpts=(d.workouts||[]).reduce((a,w)=>a+([0,15,30,60][w]||0),0);const journalCount=(d.journal?.length||0);return(<div style={cs.sec}><Section label="Body" open={open.body} onToggle={()=>tog("body")}><RowItem label="Brush teeth" pts={((d.brushAM?1:0)+(d.brushPM?1:0))*10} right={<div style={{display:"flex",gap:8,alignItems:"center"}}><Dots count={(d.brushAM?1:0)+(d.brushPM?1:0)} total={2}/><button style={{...cs.chip(!!(d.brushAM||d.brushPM)),position:"relative"}} onClick={()=>{if(!d.brushAM)update({brushAM:true});else if(!d.brushPM)update({brushPM:true});else update({brushAM:false,brushPM:false});}}>Smile<PtsBadge pts={10}/></button></div>}/>{[["floss","Floss",10],["shower","Shower",10],["shave","Shave",10]].map(([k,l,p])=>(<RowItem key={k} label={l} pts={d[k]?p:0} right={<Toggle on={!!d[k]} onChange={v=>update({[k]:v})} pts={p}/>}/>))}<RowItem label="Work out" pts={wpts} right={<div style={{display:"flex",gap:8,alignItems:"center"}}><Dots count={(d.workouts||[]).length} total={2}/><div style={{display:"flex",gap:6}}>{[["Lt",1,15],["Mod",2,30],["Int",3,60]].map(([label,val,p])=>{const count=(d.workouts||[]).filter(w=>w===val).length;return(<button key={val} style={{...cs.chip(count>0),background:count===2?dm.text:count===1?"#555":"transparent",color:count>0?(count===2?dm.bg:"#fff"):dm.text,borderColor:count>0?dm.text:dm.hint,position:"relative"}} onClick={()=>setModal(`workout-${val}`)}>{label}<PtsBadge pts={p}/></button>);})}</div></div>}/>{[["groom","Groom intentionally",10],["sunscreen","Apply sunscreen",10],["nap","Intentional nap",15],["breathing","Breathing exercise",15]].map(([k,l,p],i,arr)=>(<RowItem key={k} label={l} pts={d[k]?p:0} right={<Toggle on={!!d[k]} onChange={v=>update({[k]:v})} pts={p}/>} last={i===arr.length-1}/>))}</Section><Section label="Health" open={open.health} onToggle={()=>tog("health")}><RowItem label="Take medicine" pts={d.medicine?10:0} right={<Toggle on={!!d.medicine} onChange={v=>update({medicine:v})} pts={10}/>}/><RowItem label="Blood pressure" pts={(d.bp?.length||0)*10} right={<div style={{display:"flex",gap:8,alignItems:"center"}}><Dots count={d.bp?.length||0} total={2}/><button style={{...cs.chip((d.bp?.length||0)>0),position:"relative"}} onClick={()=>(d.bp?.length||0)<2&&setModal("bp")}>Log<PtsBadge pts={10}/></button></div>}/><RowItem label="Log weight" pts={d.weight?10:0} right={<button style={{...cs.chip(!!d.weight),position:"relative"}} onClick={()=>setModal("weight")}>{d.weight?`${d.weight} lbs`:"Log"}<PtsBadge pts={10}/></button>} last/></Section><Section label="Soul" open={open.soul} onToggle={()=>tog("soul")}><RowItem label="Read scripture" pts={[0,15,25,35][d.scripture]||0} right={<div style={{display:"flex",gap:6}}>{["10m","20m","30m+"].map((l,i)=>(<button key={i} style={{...cs.chip(d.scripture===i+1),position:"relative"}} onClick={()=>setModal(`scripture-${i+1}`)}>{l}<PtsBadge pts={[15,25,35][i]}/></button>))}</div>}/><RowItem label="Prayer" pts={d.prayer?.duration?[0,15,25,35][d.prayer.duration]||0:0} right={<div style={{display:"flex",gap:6}}>{["5m","15m","25m+"].map((l,i)=>(<button key={i} style={{...cs.chip((d.prayer?.duration||0)===i+1),position:"relative"}} onClick={()=>setModal(`prayer-${i+1}`)}>{l}<PtsBadge pts={[15,25,35][i]}/></button>))}</div>}/><RowItem label="Emotional check-in" pts={(d.emotions?.length||0)*10} right={<div style={{display:"flex",gap:8,alignItems:"center"}}><Dots count={d.emotions?.length||0} total={4}/><button style={{...cs.chip((d.emotions?.length||0)>0),position:"relative"}} onClick={()=>setModal("emotion")}>{EMOTION_BTN}<PtsBadge pts={10}/></button></div>}/>{(d.emotions||[]).map((e,i)=>(<div key={i} style={{padding:"2px 16px 4px",fontSize:12,color:dm.hint}}>{e.core}{e.mid?` - ${e.mid}`:""}{e.specific?` - ${e.specific}`:""}</div>))}<RowItem label="Connect with someone" pts={d.connect?30:0} right={<button style={{...cs.chip(!!d.connect),position:"relative"}} onClick={()=>setModal("connect")}>{d.connectNote?d.connectNote.slice(0,10)+(d.connectNote.length>10?"...":""):"Heyyy"}<PtsBadge pts={30}/></button>} last/></Section><Section label="Mind" open={open.mind} onToggle={()=>tog("mind")}>{[["planDay","Plan your day",20],["notifZero","Notifications to zero",20],["emailZero","Email to zero",25]].map(([k,l,p])=>(<RowItem key={k} label={l} pts={d[k]?p:0} right={<Toggle on={!!d[k]} onChange={v=>update({[k]:v})} pts={p}/>}/>))}<RowItem label="Complete avoided task" pts={d.avoidedTask?50:0} right={<button style={{...cs.chip(!!d.avoidedTask),position:"relative"}} onClick={()=>setModal("avoidedTask")}>{d.avoidedTaskNote?d.avoidedTaskNote.slice(0,10)+(d.avoidedTaskNote.length>10?"...":""):"Slay"}<PtsBadge pts={50}/></button>}/><RowItem label="Phone-free walk" pts={[0,20,40,70][d.walk]||0} right={<div style={{display:"flex",gap:6}}>{[["10m",1,20],["30m",2,40],["60m+",3,70]].map(([l,val,p])=>(<button key={val} style={{...cs.chip(d.walk===val),position:"relative"}} onClick={()=>update({walk:d.walk===val?0:val})}>{l}<PtsBadge pts={p}/></button>))}</div>}/><RowItem label="Journal" pts={Math.min(3,journalCount)*20} right={<div style={{display:"flex",gap:8,alignItems:"center"}}><Dots count={Math.min(3,journalCount)} total={3}/><button style={{...cs.chip(journalCount>0),position:"relative"}} onClick={()=>setModal("journal")}>{journalCount>=3?"Fanfic again":"Fanfic"}<PtsBadge pts={20}/></button></div>}/><RowItem label="Read a book" pts={[0,25,45,70][d.readBook]||0} right={<div style={{display:"flex",gap:6}}>{[["20m",1,25],["40m",2,45],["60m+",3,70]].map(([l,val,p])=>(<button key={val} style={{...cs.chip(d.readBook===val),position:"relative"}} onClick={()=>setModal(`readBook-${val}`)}>{l}<PtsBadge pts={p}/></button>))}</div>} last/></Section><Section label="Food" open={open.food} onToggle={()=>tog("food")}><CalorieDisplay d={d}/><RowItem label="Meals" pts={((d.meals?.breakfast?1:0)+(d.meals?.lunch?1:0)+(d.meals?.dinner?1:0))*10+(d.snacks?.length||0)*3+(d.tasteJournal?10:0)} right={<div style={{display:"flex",gap:6,flexWrap:"wrap",justifyContent:"flex-end"}}>{["breakfast","lunch","dinner"].map(m=>(<button key={m} style={{...cs.chip(!!d.meals?.[m]),position:"relative"}} onClick={()=>setModal(`meal-${m}`)}>{m.charAt(0).toUpperCase()+m.slice(1)}<PtsBadge pts={10}/></button>))}<button style={{...cs.chip(false),position:"relative"}} onClick={()=>setModal("snack")}>Snack{(d.snacks?.length||0)>0?` (${d.snacks.length})`:""}<PtsBadge pts={3}/></button></div>}/>{[["cookMeal","Cook a meal at home",30],["platFood","Plate your food nicely",15]].map(([k,l,p])=>(<RowItem key={k} label={l} pts={d[k]?p:0} right={<Toggle on={!!d[k]} onChange={v=>update({[k]:v})} pts={p}/>}/>))}<RowItem label="Water refills" pts={(d.waterRefills||0)*5} right={<div style={{display:"flex",alignItems:"center",gap:10}}><button style={cs.cBtn} onClick={()=>update({waterRefills:Math.max(0,(d.waterRefills||0)-1)})}>-</button><span style={{fontSize:16,minWidth:20,textAlign:"center",color:dm.text}}>{d.waterRefills||0}</span><button style={cs.cBtn} onClick={()=>update({waterRefills:(d.waterRefills||0)+1})}>+</button></div>} last/></Section><Section label="Home" open={open.home} onToggle={()=>tog("home")}>{[["makeBed","Make bed",10],["mowLawn","Mow the lawn",80]].map(([k,l,p])=>(<RowItem key={k} label={l} pts={d[k]?p:0} right={<Toggle on={!!d[k]} onChange={v=>update({[k]:v})} pts={p}/>}/>))}<RowItem label="Cleaning session" pts={[0,20,40,70][d.cleaning?.tier]||0} right={<div style={{display:"flex",gap:6}}>{[["10m",1,20],["30m",2,40],["60m+",3,70]].map(([l,val,p])=>(<button key={val} style={{...cs.chip((d.cleaning?.tier||0)===val),position:"relative"}} onClick={()=>setModal(`cleaning-${val}`)}>{l}<PtsBadge pts={p}/></button>))}</div>} last/></Section></div>);}

function HistoryView({allData,goal}){const days=[];for(let i=0;i<60;i++){const dt=new Date();dt.setDate(dt.getDate()-i);const k=dt.toISOString().slice(0,10);days.push({k,pts:calcPoints(allData[k]||defaultDay()),label:dt.toLocaleDateString("en-US",{month:"short",day:"numeric"}),hasData:!!allData[k]});}return(<div style={cs.sec}><div style={{paddingBottom:10}}><span style={cs.secHead}>Last 60 days</span></div><div style={cs.card}>{days.map(({k,pts,label,hasData},i)=>{const pct=Math.min(100,Math.round((pts/goal)*100)),met=pts>=goal,partial=pts>=goal*0.55;return(<div key={k}><div style={{...cs.row,minHeight:52}}><span style={{fontSize:14,color:dm.subtext,minWidth:60}}>{label}</span><div style={{flex:1,margin:"0 10px"}}><div style={{height:8,borderRadius:4,background:dm.border,overflow:"hidden"}}><div style={{height:"100%",width:`${pct}%`,background:met?dm.green:partial?dm.orange:dm.blue,borderRadius:4,transition:"width 0.4s"}}/></div></div><span style={{fontSize:14,fontWeight:500,minWidth:32,textAlign:"right",color:dm.text}}>{pts}</span>{hasData&&<span style={cs.badge(met)}>{met?"Goal":partial?"~":"Low"}</span>}</div>{i<days.length-1&&<div style={cs.divider}/>}</div>);})}</div></div>);}

function SettingsView({settings,saveSettings,allData,apiKey,saveApiKey,onSignOut,wipeToday}){const[keyVal,setKeyVal]=useState(apiKey||"");const[keyVisible,setKeyVisible]=useState(false);const[confirmWipe,setConfirmWipe]=useState(false);function exportCSV(){
  const yn=v=>v?"Yes":"No";
  const scrLbl=["","10 min","20 min","30+ min"];
  const prayLbl=["","5 min","15 min","25+ min"];
  const walkLbl=["","10 min","30 min","60+ min"];
  const bookLbl=["","20 min","40 min","60+ min"];
  const cleanLbl=["","10 min","30 min","60+ min"];
  const wrkLbl=["","Light","Moderate","Intense"];
  const headers=["Date","Points","Goal Met","Daily Goal",
    "Brush AM","Brush PM","Floss","Shower","Shave",
    "Workouts","Workout Note","Push-ups","Groom","Sunscreen","Nap","Breathing",
    "Medicine","BP Reading 1","BP Reading 2","Weight",
    "Scripture","Scripture Note","Prayer","Prayer Topic",
    "Emotions","Emotion Notes","Connected With",
    "Plan Day","Notifs to Zero","Email to Zero","Avoided Task","Avoided Task Note",
    "Walk","Journal Count","Journal Prompts","Journal Responses","Read Book","Reading Note",
    "Breakfast","Lunch","Dinner","Snacks","Cook Meal","Water Refills","Plate Food","Taste Journal",
    "Make Bed","Mow Lawn","Cleaning Session","Cleaning Areas"];
  const rows=[headers];
  Object.keys(allData).sort().forEach(k=>{
    const d=allData[k],pts=calcPoints(d);
    const bp1=d.bp?.[0]?`${d.bp[0].sys}/${d.bp[0].dia} @ ${d.bp[0].time}`:"";
    const bp2=d.bp?.[1]?`${d.bp[1].sys}/${d.bp[1].dia} @ ${d.bp[1].time}`:"";
    const journals=d.journal||[];
    const emotions=(d.emotions||[]).map(e=>[e.core,e.mid,e.specific].filter(Boolean).join(" > ")).join(" | ");
    const emotionNotes=(d.emotions||[]).map(e=>e.note||"").filter(Boolean).join(" | ");
    rows.push([
      k,pts,pts>=settings.daily?"Yes":"No",settings.daily,
      yn(d.brushAM),yn(d.brushPM),yn(d.floss),yn(d.shower),yn(d.shave),
      (d.workouts||[]).map(w=>wrkLbl[w]).join(" + "),d.workoutNote||"",d.pushups||"",
      yn(d.groom),yn(d.sunscreen),yn(d.nap),yn(d.breathing),
      yn(d.medicine),bp1,bp2,d.weight||"",
      scrLbl[d.scripture||0],d.scriptureNote||"",
      prayLbl[d.prayer?.duration||0],d.prayer?.topic||"",
      emotions,emotionNotes,d.connectNote||"",
      yn(d.planDay),yn(d.notifZero),yn(d.emailZero),yn(d.avoidedTask),d.avoidedTaskNote||"",
      walkLbl[d.walk||0],journals.length,
      journals.map(e=>e.prompt).join(" | "),
      journals.map(e=>e.response).join(" | "),
      bookLbl[d.readBook||0],d.readBookNote||"",
      d.meals?.breakfast||"",d.meals?.lunch||"",d.meals?.dinner||"",
      (d.snacks||[]).join(" | "),
      yn(d.cookMeal),d.waterRefills||0,yn(d.platFood),d.tasteJournal||"",
      yn(d.makeBed),yn(d.mowLawn),cleanLbl[d.cleaning?.tier||0],(d.cleaning?.subs||[]).join(", ")
    ].map(v=>`"${String(v).replace(/"/g,'""')}"`));
  });
  const a=document.createElement("a");
  a.href="data:text/csv;charset=utf-8,"+encodeURIComponent(rows.map(r=>r.join(",")).join("\n"));
  a.download="habits.csv";
  a.click();
}return(<div style={cs.sec}><div style={{paddingBottom:10}}><span style={cs.secHead}>Goals</span></div><div style={cs.card}><div style={{padding:"14px 16px"}}><label style={{fontSize:14,color:dm.subtext,display:"block",marginBottom:6}}>Daily point goal</label><input style={cs.inp} type="number" value={settings.daily} onChange={e=>saveSettings({...settings,daily:Number(e.target.value)})}/></div><div style={cs.divider}/><div style={{padding:"14px 16px"}}><label style={{fontSize:14,color:dm.subtext,display:"block",marginBottom:6}}>Weekly point goal</label><input style={cs.inp} type="number" value={settings.weekly} onChange={e=>saveSettings({...settings,weekly:Number(e.target.value)})}/></div></div><div style={{paddingTop:24,paddingBottom:10}}><span style={cs.secHead}>Calorie estimation</span></div><div style={cs.card}><div style={{padding:"14px 16px"}}><label style={{fontSize:14,color:dm.subtext,display:"block",marginBottom:6}}>Anthropic API key</label><div style={{display:"flex",gap:8}}><input style={{...cs.inp,flex:1}} type={keyVisible?"text":"password"} placeholder="sk-ant-..." value={keyVal} onChange={e=>setKeyVal(e.target.value)}/><button style={{...cs.chip(false),flexShrink:0}} onClick={()=>setKeyVisible(v=>!v)}>{keyVisible?"Hide":"Show"}</button></div><p style={{fontSize:12,color:dm.hint,marginTop:8}}>Used only for calorie estimates. Stored locally in your browser.</p></div></div><button style={{...cs.bigBtn(true),marginTop:10}} onClick={()=>saveApiKey(keyVal)}>Save key</button><div style={{paddingTop:24,paddingBottom:10}}><span style={cs.secHead}>Data</span></div><button style={{...cs.bigBtn(false)}} onClick={exportCSV}>Export CSV backup</button><p style={{fontSize:13,color:dm.hint,marginTop:8,paddingBottom:16}}>Exports all {Object.keys(allData).length} logged days.</p><div style={{paddingTop:8,paddingBottom:10}}><span style={cs.secHead}>Account</span></div><button style={{...cs.bigBtn(false),...(confirmWipe?{color:dm.red,borderColor:dm.red}:{})}} onClick={()=>{if(confirmWipe){wipeToday();setConfirmWipe(false);}else setConfirmWipe(true);}}>{confirmWipe?"Tap again to confirm":"Wipe today's data"}</button><button style={{...cs.bigBtn(false),color:dm.red,borderColor:dm.red,marginTop:10}} onClick={onSignOut}>Sign out</button></div>);}

export default function Tracker({session}){
  const[view,setView]=useState("today");
  const[allData,setAllData]=useState({});
  const[modal,setModal]=useState(null);
  const[settings,setSettings]=useState({daily:DAILY_GOAL,weekly:WEEKLY_GOAL});
  const[apiKey,setApiKey]=useState("");
  const[searching,setSearching]=useState(false);
  const[saving,setSaving]=useState(false);
  const bannerRef=useRef(null);

  // Load all data from Supabase on mount
  useEffect(()=>{
    async function load(){
      const[{data:rows,error},{data:{user}}]=await Promise.all([
        supabase.from('habit_days').select('date,data').eq('user_id',session.user.id),
        supabase.auth.getUser(),
      ]);
      if(error){console.error(error);return;}
      if(user?.user_metadata?.settings)setSettings(user.user_metadata.settings);
      const map={};rows.forEach(row=>{if(row.date!=='__settings__')map[row.date]=row.data;});
      setAllData(map);
    }
    // localStorage gives fast initial load; Supabase overrides with synced value
    const s=localStorage.getItem('hq_settings');if(s)setSettings(JSON.parse(s));
    const k=localStorage.getItem('hq_apikey');if(k)setApiKey(k);
    load();
  },[session]);

  const today=todayKey();
  const d=allData[today]||defaultDay();

  async function update(patch){
    const newD={...d,...patch};
    setAllData(prev=>({...prev,[today]:newD}));
    setSaving(true);
    await supabase.from('habit_days').upsert({user_id:session.user.id,date:today,data:newD,updated_at:new Date().toISOString()},{onConflict:'user_id,date'});
    setSaving(false);
  }

  function saveSettings(s){setSettings(s);localStorage.setItem('hq_settings',JSON.stringify(s));supabase.auth.updateUser({data:{settings:s}});}
  function saveApiKey(k){setApiKey(k);localStorage.setItem('hq_apikey',k);}
  async function wipeToday(){const fresh=defaultDay();setAllData(prev=>({...prev,[today]:fresh}));setSaving(true);await supabase.from('habit_days').upsert({user_id:session.user.id,date:today,data:fresh,updated_at:new Date().toISOString()},{onConflict:'user_id,date'});setSaving(false);}
  async function signOut(){await supabase.auth.signOut();}

  const pts=calcPoints(d);
  const pct=Math.min(100,Math.round((pts/settings.daily)*100));
  const weekPts=(()=>{let t=0;for(let i=0;i<7;i++){const dt=new Date();dt.setDate(dt.getDate()-i);t+=calcPoints(allData[dt.toISOString().slice(0,10)]||defaultDay());}return t;})();
  const mealKey=modal&&modal.startsWith("meal-")?modal.slice(5):null;
  const barColor=pts>=settings.daily?dm.green:pts>=settings.daily*0.55?dm.orange:dm.blue;
  const turtleState=pts>=settings.daily?3:pts>=settings.daily*0.67?2:pts>=settings.daily*0.34?1:0;
  const streak=(()=>{let s=0;const t=new Date();for(let i=0;i<365;i++){const dt=new Date(t);dt.setDate(dt.getDate()-i);const k=dt.toISOString().slice(0,10);if(calcPoints(allData[k]||{})<1)break;s++;}return s;})();

  useEffect(()=>{
    const canvas=bannerRef.current;if(!canvas)return;
    const ctx=canvas.getContext('2d');ctx.imageSmoothingEnabled=false;
    let frame=0,tick=0,animId;
    function loop(){tick++;if(tick%2===0){frame++;bDrawBackground(ctx,frame%8,frame,turtleState,streak);bDrawTurtle(ctx,turtleState,frame);bDrawTitle(ctx,turtleState,streak);}animId=requestAnimationFrame(loop);}
    loop();return()=>cancelAnimationFrame(animId);
  },[turtleState,streak]);

  return(
    <div style={cs.wrap}>
      {searching&&<SearchBar setModal={setModal} d={d} update={update} onClose={()=>setSearching(false)}/>}
      {modal&&modal.startsWith("scripture-")&&<ScriptureSheet d={d} tier={Number(modal.split("-")[1])} update={update} onClose={()=>setModal(null)}/>}
      {modal&&modal.startsWith("prayer-")&&<PrayerSheet d={d} tier={Number(modal.split("-")[1])} update={update} onClose={()=>setModal(null)}/>}
      {modal&&modal.startsWith("workout-")&&<WorkoutSheet d={d} val={Number(modal.split("-")[1])} update={update} onClose={()=>setModal(null)}/>}
      {modal&&modal.startsWith("readBook-")&&<ReadBookSheet d={d} tier={Number(modal.split("-")[1])} update={update} onClose={()=>setModal(null)}/>}
      {modal&&modal.startsWith("cleaning-")&&<CleaningSheet d={d} tier={Number(modal.split("-")[1])} update={update} onClose={()=>setModal(null)}/>}
      {modal==="weight"&&<WeightSheet weight={d.weight} onChange={v=>update({weight:v})} onClose={()=>setModal(null)}/>}
      {modal==="bp"&&<BPSheet bp={d.bp||[]} onChange={v=>update({bp:v})} onClose={()=>setModal(null)}/>}
      {modal==="emotion"&&<EmotionSheet emotions={d.emotions||[]} onChange={v=>update({emotions:v})} onClose={()=>setModal(null)}/>}
      {modal==="journal"&&<JournalSheet d={d} update={update} onClose={()=>setModal(null)}/>}
      {modal==="avoidedTask"&&<AvoidedTaskSheet d={d} update={update} onClose={()=>setModal(null)}/>}
      {modal==="connect"&&<ConnectSheet d={d} update={update} onClose={()=>setModal(null)}/>}
      {modal==="taste"&&<TasteJournalSheet d={d} update={update} onClose={()=>setModal(null)}/>}
      {modal==="snack"&&<FoodSheet title="Log snack" initialValue="" onSave={v=>update({snacks:[...(d.snacks||[]),v]})} onClose={()=>setModal(null)} apiKey={apiKey} offerTaste={true} onTaste={v=>update({tasteJournal:v})}/>}
      {mealKey&&<FoodSheet title={`Log ${mealKey}`} initialValue="" onSave={v=>update({meals:{...d.meals,[mealKey]:d.meals?.[mealKey]?d.meals[mealKey]+' | '+v:v}})} onClose={()=>setModal(null)} apiKey={apiKey} offerTaste={true} onTaste={v=>update({tasteJournal:v})}/>}

      <div style={{position:"sticky",top:0,zIndex:10,background:dm.bg}}>
      <canvas ref={bannerRef} width={678} height={138} style={{width:"100%",height:"auto",imageRendering:"pixelated",display:"block"}}/>

      <div style={cs.tabs}>
        {["today","history","settings"].map(v=>(<button key={v} style={cs.tab(view===v)} onClick={()=>setView(v)}>{v.charAt(0).toUpperCase()+v.slice(1)}</button>))}
      </div>

      <div style={{background:dm.card,padding:"16px 20px 14px",borderBottom:`0.5px solid ${dm.border}`}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:14}}>
          <div>
            <div style={{fontSize:22,fontWeight:600,color:dm.text}}>Daily tracker</div>
            <div style={{fontSize:14,color:dm.subtext,marginTop:2}}>{new Date().toLocaleDateString("en-US",{weekday:"long",month:"long",day:"numeric"})}</div>
          </div>
          <div style={{display:"flex",alignItems:"flex-start",gap:10}}>
            {saving&&<span style={{fontSize:12,color:dm.hint,paddingTop:8}}>saving…</span>}
            <button onClick={()=>setSearching(true)} style={{background:dm.card2,border:"none",borderRadius:10,padding:"8px 12px",cursor:"pointer",fontSize:14,color:dm.subtext}}>Search</button>
            <div style={{textAlign:"right"}}>
              <div style={{fontSize:28,fontWeight:700,color:dm.text,lineHeight:1}}>{pts}<span style={{fontSize:15,color:dm.subtext,fontWeight:400}}>/{settings.daily}</span></div>
              <div style={{fontSize:12,color:dm.subtext,marginTop:3}}>Week: {weekPts}/{settings.weekly}</div>
            </div>
          </div>
        </div>
        <div style={{height:10,borderRadius:5,background:dm.border,overflow:"hidden"}}>
          <div style={{height:"100%",width:`${pct}%`,background:barColor,borderRadius:5,transition:"width 0.4s"}}/>
        </div>
        <div style={{display:"flex",justifyContent:"space-between",fontSize:11,color:dm.hint,marginTop:4}}>
          <span>0</span><span>{settings.daily} pts</span>
        </div>
      </div>
      </div>

      {view==="today"&&<TodayView d={d} update={update} setModal={setModal}/>}
      {view==="history"&&<HistoryView allData={allData} goal={settings.daily}/>}
      {view==="settings"&&<SettingsView settings={settings} saveSettings={saveSettings} allData={allData} apiKey={apiKey} saveApiKey={saveApiKey} onSignOut={signOut} wipeToday={wipeToday}/>}
    </div>
  );
}